UPDATE J09B_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09B_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

args.sql_query:
SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1_NET AS POST_CODE1, CITY1_NET AS CITY1, CITY2_NET AS CITY2, EMAIL
FROM J09B_temp
WHERE ENTSCHEIDUNG = 'MANDATORY_READING';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1_NET AS POST_CODE1, CITY1_NET AS CITY1, CITY2_NET AS CITY2, EMAIL
FROM J09B_temp
WHERE ENTSCHEIDUNG <> 'MANDATORY_READING' OR ENTSCHEIDUNG IS NULL;
